import 'package:http/http.dart' as http;

class HttpClient {
  final String _baseUrl = "https://api.example.com";

  Future<dynamic> fetchData() async {
    final response = await http.get(_baseUrl);
    if (response.statusCode == 200) {
      return jsonDecode(response.body);
    } else {
      throw Exception("Failed to fetch data");
    }
  }

  Future<dynamic> authenticate() async {
    final response = await http.post(_baseUrl + "/auth", body: {"username": "user@example.com", "password": "password"});
    if (response.statusCode == 200) {
      return jsonDecode(response.body);
    } else {
      throw Exception("Failed to authenticate");
    }
  }

  Future<dynamic> retrieveUserProfile() async {
    final response = await http.get(_baseUrl + "/profile", headers: {"Authorization": "Bearer ${await authenticate()}"});
    if (response.statusCode == 200) {
      return jsonDecode(response.body);
    } else {
      throw Exception("Failed to retrieve user profile");
    }
  }

  Future<dynamic> synchronizeData() async {
    final response = await http.post(_baseUrl + "/sync", body: {"data": "some data"});
    if (response.statusCode == 200) {
      return jsonDecode(response.body);
    } else {
      throw Exception("Failed to synchronize data");
    }
  }
}